arguments.command:
$REPO = "edburns/Build26-BRK206-your-agent-anywhere-multiclient-multidevice-with-github-copilot-sdk"
$BRANCH = "copilot/3-4-websocket-push-infrastructure"
$PR_NUMBER = "45"
$TIMEOUT = 600
$INTERVAL = 30
$ELAPSED = 0

while ($ELAPSED -lt $TIMEOUT) {
    $runs = gh run list -R $REPO --branch $BRANCH --json databaseId,name,status,conclusion 2>&1 | ConvertFrom-Json

    # Check if CCA is still running
    $ccaRunning = $runs | Where-Object { $_.name -eq "Running Copilot cloud agent" -and $_.status -eq "in_progress" }

    # Check for action_required runs (CI needing approval)
    $actionRequired = $runs | Where-Object { $_.status -eq "action_required" }

    # Check for completed CI runs
    $completedCI = $runs | Where-Object { $_.name -ne "Running Copilot cloud agent" -and ($_.status -eq "completed" -or $_.status -eq "in_progress") }

    Write-Host "[$ELAPSED s] CCA running: $($null -ne $ccaRunning), Action required: $($actionRequired.Count), Other CI: $($completedCI.Count)"

    if ($actionRequired.Count -gt 0) {
        Write-Host "Found action_required runs - ready to approve"
        $actionRequired | ForEach-Object { Write-Host "  Run $($_.databaseId): $($_.name)" }
        break
    }

    if (-not $ccaRunning -and $completedCI.Count -gt 0) {
        Write-Host "CCA finished and CI runs exist"
        $runs | ForEach-Object { Write-Host "  $($_.name): $($_.status) / $($_.conclusion)" }
        break
    }

    if (-not $ccaRunning -and $completedCI.Count -eq 0) {
        # CCA done but no CI yet - check pr checks
        $checks = gh pr checks $PR_NUMBER -R $REPO 2>&1
        if ($checks -notmatch "no checks reported") {
            Write-Host "Checks appeared on PR:"
            Write-Host $checks
            break
        }
    }

    Start-Sleep -Seconds $INTERVAL
    $ELAPSED += $INTERVAL
}

if ($ELAPSED -ge $TIMEOUT) {
    Write-Host "Timeout waiting for CI runs"
    gh run list -R $REPO --branch $BRANCH --json databaseId,name,status,conclusion 2>&1
}

